using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Vida, dano e reacção a dano de um inimigo (Enemy Creator — Etapa 1.3).
///
/// Lê os valores base de <see cref="EnemyController.Data"/>.stats
/// (maxHealth, knockbackResistance, weight, invincibilityTimeAfterHit,
/// canBeDestroyed, canOnlyBeDeactivated, isInvincible, recoilOnHit,
/// freezeOnHit, flashOnHit) e expõe <see cref="TakeDamage"/> como ponto de
/// entrada único para qualquer fonte de dano (contacto com o player, ataques
/// do player, hazards, outros inimigos — ver
/// EnemyWeaknessConfig.canTakeDamageFromHazards/OtherEnemyProjectiles).
///
/// Ao chegar a 0 de vida, chama EnemyController.SetState(Morto) ou
/// SetState(Desactivado) conforme "canOnlyBeDeactivated"/"canBeDestroyed"
/// (estados terminais — ver EnemyController). EnemyDropTable (Etapa 4.3) e
/// EnemyFeedback (Etapa 7.1) devem reagir a essas transições via
/// EnemyController.OnStateChanged. Para reagir apenas a "tomei dano mas não
/// morri" (ex: som de hit), usa <see cref="OnDamaged"/>.
/// </summary>
[RequireComponent(typeof(EnemyController))]
public class EnemyHealth : MonoBehaviour
{
    [Header("Janela de Vulnerabilidade (Etapa 8.3 — bosses/puzzles)")]
    [Tooltip("Se não-vazia, o inimigo SÓ é vulnerável enquanto estas condições se cumprirem (ex: Condition_GlobalBoolVariable \"GeradorDesligado\"=true, Condition_BossPartsDestroyed). Fora da janela, IsInvincible = true. Lista editável via EnemyHealthEditor.")]
    [SerializeReference] public List<EnemyCondition> vulnerabilityConditions = new List<EnemyCondition>();

    [Tooltip("Se activo, TODAS as condições de vulnerabilidade têm de se cumprir; senão, basta UMA.")]
    public bool requireAllVulnerabilityConditions = true;

    [Header("Feedback Básico (Pisca ao Tomar Dano)")]
    [Tooltip("Cor usada no pisca (ver stats.flashOnHit). Aplicada por cima da cor original do sprite, alternadamente.")]
    public Color flashColor = new Color(1f, 0.5f, 0.5f, 1f);

    [Tooltip("Duração de cada alternância do pisca, em segundos.")]
    public float flashInterval = 0.06f;

    [Tooltip("Duração total do pisca, em segundos, se 'invincibilityTimeAfterHit' for 0 (sem janela de invencibilidade definida).")]
    public float fallbackFlashDuration = 0.2f;

    private EnemyController _controller;
    private SpriteRenderer _sprite;
    private Color _baseColor;

    private int _currentHealth;
    private float _invincibleUntil;
    private EnemyState _stateBeforeStun;
    private Coroutine _flashRoutine;
    private Coroutine _stunRoutine;

    /// <summary>Vida máxima (EnemyData.stats.maxHealth). 1 se "data" não estiver definido.</summary>
    public int MaxHealth => _controller.Data != null ? Mathf.Max(1, _controller.Data.stats.maxHealth) : 1;

    /// <summary>Vida actual (0..MaxHealth).</summary>
    public int CurrentHealth => _currentHealth;

    /// <summary>Vida actual / vida máxima (0..1).</summary>
    public float HealthPercent => (float)_currentHealth / MaxHealth;

    /// <summary>
    /// True se "stats.isInvincible" estiver activo, se ainda estiver dentro da
    /// janela de invencibilidade pós-hit, OU se a janela de vulnerabilidade
    /// (Etapa 8.3 — "vulnerável quando X") não estiver aberta.
    /// </summary>
    public bool IsInvincible
    {
        get
        {
            var stats = _controller.Data != null ? _controller.Data.stats : null;
            if (stats != null && stats.isInvincible) return true;
            if (Time.time < _invincibleUntil) return true;
            return !IsVulnerableByConditions();
        }
    }

    /// <summary>Avalia a janela de vulnerabilidade (Etapa 8.3). Lista vazia = sempre vulnerável.</summary>
    private bool IsVulnerableByConditions()
    {
        if (vulnerabilityConditions == null || vulnerabilityConditions.Count == 0) return true;

        bool any = false;

        for (int i = 0; i < vulnerabilityConditions.Count; i++)
        {
            var condition = vulnerabilityConditions[i];
            if (condition == null) continue;

            bool ok = condition.Evaluate(_controller);

            if (requireAllVulnerabilityConditions && !ok) return false;
            if (!requireAllVulnerabilityConditions && ok) any = true;
        }

        return requireAllVulnerabilityConditions || any;
    }

    /// <summary>Disparado quando o inimigo toma dano e sobrevive: (quantidade de dano, vida actual).</summary>
    public event Action<int, int> OnDamaged;

    /// <summary>Disparado quando a vida muda (vida actual, vida máxima) — inclui dano e cura.</summary>
    public event Action<int, int> OnHealthChanged;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _sprite = _controller.SpriteRenderer;
        if (_sprite != null) _baseColor = _sprite.color;

        ResetHealth();
    }

    private void OnDisable()
    {
        if (_flashRoutine != null) StopCoroutine(_flashRoutine);
        if (_stunRoutine != null) StopCoroutine(_stunRoutine);

        if (_sprite != null) _sprite.color = _baseColor;
    }

    /// <summary>
    /// Repõe a vida ao máximo e limpa invencibilidade/estados de hit. Usado em
    /// Awake e pela lógica de respawn (Etapa 7.3).
    /// </summary>
    public void ResetHealth()
    {
        _currentHealth = MaxHealth;
        _invincibleUntil = 0f;
        OnHealthChanged?.Invoke(_currentHealth, MaxHealth);
    }

    /// <summary>Cura o inimigo (sem exceder o máximo). Útil para itens/efeitos futuros.</summary>
    public void Heal(int amount)
    {
        if (amount <= 0 || _currentHealth <= 0) return;
        if (_controller.IsTerminal) return;

        _currentHealth = Mathf.Min(MaxHealth, _currentHealth + amount);
        OnHealthChanged?.Invoke(_currentHealth, MaxHealth);
    }

    /// <summary>Aplica dano sem origem nem knockback (ex: hazards de área).</summary>
    public bool TakeDamage(int amount)
    {
        return TakeDamage(amount, transform.position, 0f);
    }

    /// <summary>
    /// Aplica dano de um ataque feito numa forma "attackerCategory" do player
    /// (GDD 12.1: "dano não é fixo; depende da força do animal e da habilidade
    /// usada"). Se "attackerCategory" tiver alguma categoria em comum com
    /// <see cref="EnemyData.weaknesses"/>.weakAgainst, o dano é multiplicado por
    /// "weaknesses.weaknessDamageMultiplier" (mínimo 1) antes de ser aplicado
    /// normalmente — ver <see cref="TakeDamage(int, Vector2, float)"/> para o
    /// resto do comportamento (invencibilidade, knockback, etc).
    /// </summary>
    public bool TakeDamage(int amount, AnimalCategory attackerCategory, Vector2 hitOrigin, float knockbackForce = 0f)
    {
        var weaknesses = _controller.Data != null ? _controller.Data.weaknesses : null;

        int effectiveAmount = amount;
        if (weaknesses != null && attackerCategory != AnimalCategory.None && (weaknesses.weakAgainst & attackerCategory) != 0)
            effectiveAmount = Mathf.Max(1, Mathf.RoundToInt(amount * weaknesses.weaknessDamageMultiplier));

        return TakeDamage(effectiveAmount, hitOrigin, knockbackForce);
    }

    /// <summary>
    /// Aplica dano vindo de "hitOrigin" (usado para calcular a direcção do
    /// knockback) com força de knockback "knockbackForce". Devolve false sem
    /// qualquer efeito se o inimigo for invencível (stats.isInvincible ou
    /// dentro da janela pós-hit) ou já estiver num estado terminal
    /// (Morto/Desactivado).
    /// </summary>
    public bool TakeDamage(int amount, Vector2 hitOrigin, float knockbackForce = 0f)
    {
        if (amount <= 0) return false;
        if (_controller.IsTerminal) return false;
        if (IsInvincible) return false;

        var stats = _controller.Data != null ? _controller.Data.stats : null;

        _currentHealth = Mathf.Max(0, _currentHealth - amount);
        OnHealthChanged?.Invoke(_currentHealth, MaxHealth);
        OnDamaged?.Invoke(amount, _currentHealth);

        if (stats != null && stats.invincibilityTimeAfterHit > 0f)
            _invincibleUntil = Time.time + stats.invincibilityTimeAfterHit;

        bool flash = stats == null || stats.flashOnHit;
        bool recoil = stats != null && stats.recoilOnHit;
        bool freeze = stats != null && stats.freezeOnHit;

        if (flash) StartFlash(stats != null ? stats.invincibilityTimeAfterHit : 0f);
        if (recoil) ApplyKnockback(hitOrigin, knockbackForce, stats);

        if (_currentHealth <= 0)
        {
            HandleDeath(stats);
            return true;
        }

        if (freeze) StartStun(stats != null ? stats.invincibilityTimeAfterHit : 0f);

        return true;
    }

    /// <summary>Força a destruição/desactivação imediata, ignorando dano e invencibilidade (ex: interacção de puzzle — Etapa 6).</summary>
    public void Kill()
    {
        if (_controller.IsTerminal) return;

        _currentHealth = 0;
        OnHealthChanged?.Invoke(_currentHealth, MaxHealth);
        HandleDeath(_controller.Data != null ? _controller.Data.stats : null);
    }

    private void HandleDeath(EnemyStats stats)
    {
        if (stats != null && stats.canOnlyBeDeactivated)
        {
            _controller.SetState(EnemyState.Desactivado);
        }
        else if (stats == null || stats.canBeDestroyed)
        {
            _controller.SetState(EnemyState.Morto);
        }
        else
        {
            // Nem destruível nem apenas-desactivável: a vida fica a 0 mas o
            // inimigo continua activo (ex: configuração incompleta). Não muda
            // de estado.
            _currentHealth = 0;
        }
    }

    /// <summary>
    /// Aplica um impulso de empurrão a este inimigo sem causar dano nem
    /// invencibilidade — usado por habilidades de empurrão sem ataque (ex:
    /// RollAbility do Pangolim, "rolar contra inimigos").
    /// </summary>
    public void ApplyExternalKnockback(Vector2 hitOrigin, float knockbackForce)
    {
        ApplyKnockback(hitOrigin, knockbackForce, _controller.Data != null ? _controller.Data.stats : null);
    }

    private void ApplyKnockback(Vector2 hitOrigin, float knockbackForce, EnemyStats stats)
    {
        if (knockbackForce <= 0f) return;
        if (_controller.Rb == null) return;

        Vector2 direction = (Vector2)transform.position - hitOrigin;
        if (direction.sqrMagnitude < 0.0001f) return;
        direction.Normalize();

        float resistance = stats != null ? Mathf.Clamp01(stats.knockbackResistance) : 0f;
        float weight = stats != null && stats.weight > 0f ? stats.weight : 1f;

        float effectiveForce = knockbackForce * (1f - resistance) / weight;
        if (effectiveForce <= 0f) return;

        _controller.Rb.AddForce(direction * effectiveForce, ForceMode2D.Impulse);
    }

    private void StartStun(float duration)
    {
        if (duration <= 0f) return;
        if (_stunRoutine != null) StopCoroutine(_stunRoutine);

        _stateBeforeStun = _controller.State;
        _controller.SetState(EnemyState.Atordoado);
        _stunRoutine = StartCoroutine(StunRoutine(duration));
    }

    private IEnumerator StunRoutine(float duration)
    {
        yield return new WaitForSeconds(duration);

        if (_controller.State == EnemyState.Atordoado)
            _controller.SetState(_stateBeforeStun);

        _stunRoutine = null;
    }

    private void StartFlash(float duration)
    {
        if (_sprite == null) return;
        if (duration <= 0f) duration = fallbackFlashDuration;
        if (_flashRoutine != null) StopCoroutine(_flashRoutine);

        _flashRoutine = StartCoroutine(FlashRoutine(duration));
    }

    private IEnumerator FlashRoutine(float duration)
    {
        float elapsed = 0f;
        bool toggled = false;

        while (elapsed < duration)
        {
            toggled = !toggled;
            _sprite.color = toggled ? flashColor : _baseColor;

            yield return new WaitForSeconds(flashInterval);
            elapsed += flashInterval;
        }

        _sprite.color = _baseColor;
        _flashRoutine = null;
    }
}
